import { Context, Next } from 'hono';
import { db, users, roles, sessions } from '../db';
import { eq, and } from 'drizzle-orm';

// Extend Hono context to include user info
declare module 'hono' {
  interface ContextVariableMap {
    user: {
      id: string;
      username: string;
      email: string;
      displayName: string;
      avatar: string | null;
      roleId: string | null;
      status: string;
      role: {
        id: string;
        name: string;
        permissions: Record<string, Record<string, boolean>>;
      } | null;
    };
    sessionId: string;
  }
}

/**
 * Authentication middleware
 * Validates Bearer token from Authorization header,
 * checks session validity in database, and attaches user info to context.
 */
export async function authMiddleware(c: Context, next: Next) {
  const authHeader = c.req.header('Authorization');

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return c.json(
      { success: false, message: '未授权：缺少 Authorization 头' },
      401
    );
  }

  const token = authHeader.slice(7); // Remove 'Bearer ' prefix

  if (!token) {
    return c.json(
      { success: false, message: '未授权：Token 为空' },
      401
    );
  }

  try {
    // Find session by token with user and role info
    const session = await db.query.sessions.findFirst({
      where: eq(sessions.token, token),
      with: {
        user: {
          with: { role: true },
        },
      },
    });

    if (!session) {
      return c.json(
        { success: false, message: '未授权：无效的 Token' },
        401
      );
    }

    // Check if session is expired
    const expiresAt = new Date(session.expiresAt);
    if (expiresAt < new Date()) {
      // Clean up expired session
      await db.delete(sessions).where(eq(sessions.id, session.id));
      return c.json(
        { success: false, message: '未授权：会话已过期，请重新登录' },
        401
      );
    }

    // Check if user is active
    if (session.user.status !== 'active') {
      return c.json(
        { success: false, message: '账号已被禁用，请联系管理员' },
        403
      );
    }

    // Parse role permissions
    let roleWithPermissions = session.user.role;
    if (roleWithPermissions && typeof roleWithPermissions.permissions === 'string') {
      try {
        roleWithPermissions = {
          ...roleWithPermissions,
          permissions: JSON.parse(roleWithPermissions.permissions as string),
        };
      } catch {
        roleWithPermissions = {
          ...roleWithPermissions,
          permissions: {},
        };
      }
    }

    // Attach user info to context
    c.set('user', {
      id: session.user.id,
      username: session.user.username,
      email: session.user.email,
      displayName: session.user.displayName,
      avatar: session.user.avatar,
      roleId: session.user.roleId,
      status: session.user.status,
      role: roleWithPermissions
        ? {
            id: roleWithPermissions.id,
            name: roleWithPermissions.name,
            permissions: roleWithPermissions.permissions as Record<string, Record<string, boolean>>,
          }
        : null,
    });
    c.set('sessionId', session.id);

    await next();
  } catch (error) {
    console.error('Auth middleware error:', error);
    return c.json(
      { success: false, message: '服务器错误：认证失败' },
      500
    );
  }
}

/**
 * Role-based access control middleware factory
 * Creates middleware that checks if user has required permission.
 *
 * @param module - The module to check permission for (e.g., 'patients', 'studies', 'reports')
 * @param action - The action to check (e.g., 'create', 'read', 'update', 'delete')
 */
export function requirePermission(module: string, action: string) {
  return async (c: Context, next: Next) => {
    const user = c.get('user');

    if (!user) {
      return c.json(
        { success: false, message: '未授权：用户信息未找到' },
        401
      );
    }

    // Admin users bypass permission checks
    if (user.role?.name === '管理员') {
      await next();
      return;
    }

    if (!user.role) {
      return c.json(
        { success: false, message: '权限不足：未分配角色' },
        403
      );
    }

    const permissions = user.role.permissions;
    const hasPermission = permissions?.[module]?.[action] === true;

    if (!hasPermission) {
      return c.json(
        {
          success: false,
          message: `权限不足：需要 ${module}:${action} 权限`,
        },
        403
      );
    }

    await next();
  };
}

/**
 * Optional auth middleware
 * Attaches user info if token is present, but doesn't block the request.
 */
export async function optionalAuth(c: Context, next: Next) {
  const authHeader = c.req.header('Authorization');

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    await next();
    return;
  }

  const token = authHeader.slice(7);

  if (!token) {
    await next();
    return;
  }

  try {
    const session = await db.query.sessions.findFirst({
      where: eq(sessions.token, token),
      with: {
        user: {
          with: { role: true },
        },
      },
    });

    if (session && new Date(session.expiresAt) >= new Date() && session.user.status === 'active') {
      let roleWithPermissions = session.user.role;
      if (roleWithPermissions && typeof roleWithPermissions.permissions === 'string') {
        try {
          roleWithPermissions = {
            ...roleWithPermissions,
            permissions: JSON.parse(roleWithPermissions.permissions as string),
          };
        } catch {
          roleWithPermissions = {
            ...roleWithPermissions,
            permissions: {},
          };
        }
      }

      c.set('user', {
        id: session.user.id,
        username: session.user.username,
        email: session.user.email,
        displayName: session.user.displayName,
        avatar: session.user.avatar,
        roleId: session.user.roleId,
        status: session.user.status,
        role: roleWithPermissions
          ? {
              id: roleWithPermissions.id,
              name: roleWithPermissions.name,
              permissions: roleWithPermissions.permissions as Record<string, Record<string, boolean>>,
            }
          : null,
      });
      c.set('sessionId', session.id);
    }
  } catch (error) {
    // Silently fail for optional auth
    console.warn('Optional auth failed:', error);
  }

  await next();
}

import { Context, Next } from 'hono';
import { db, auditLogs } from '../db';
import { v4 as uuid } from 'uuid';

/**
 * Audit log entry structure
 */
interface AuditLogEntry {
  userId: string;
  action: string;
  resource: string;
  resourceId?: string;
  details?: Record<string, any>;
  ipAddress?: string;
}

/**
 * Create an audit log entry
 * Can be called directly from route handlers for specific actions.
 */
export async function createAuditLog(entry: AuditLogEntry): Promise<void> {
  try {
    await db.insert(auditLogs).values({
      id: uuid(),
      userId: entry.userId,
      action: entry.action,
      resource: entry.resource,
      resourceId: entry.resourceId || null,
      details: entry.details ? JSON.stringify(entry.details) : null,
      ipAddress: entry.ipAddress || null,
      createdAt: new Date().toISOString(),
    });
  } catch (error) {
    // Don't let audit log failures break the request
    console.error('Failed to create audit log:', error);
  }
}

/**
 * Audit middleware factory
 * Creates middleware that logs user actions after the request completes.
 *
 * @param action - The action being performed (e.g., 'create', 'update', 'delete')
 * @param resource - The resource being acted upon (e.g., 'patient', 'study', 'report')
 */
export function auditLog(action: string, resource: string) {
  return async (c: Context, next: Next) => {
    // Execute the route handler first
    await next();

    // Only log for successful mutations (POST, PUT, DELETE)
    const method = c.req.method;
    if (!['POST', 'PUT', 'DELETE', 'PATCH'].includes(method)) {
      return;
    }

    // Only log if response is successful
    const status = c.res.status;
    if (status >= 400) {
      return;
    }

    // Get user from context (set by auth middleware)
    const user = c.get('user');
    if (!user) {
      return;
    }

    // Extract resource ID from URL if present
    const url = new URL(c.req.url);
    const pathParts = url.pathname.split('/').filter(Boolean);
    // Try to find an ID in the path (e.g., /api/patients/123 -> 123)
    let resourceId: string | undefined;
    if (pathParts.length >= 2) {
      const lastPart = pathParts[pathParts.length - 1];
      // Check if it looks like a UUID or numeric ID
      if (lastPart && /^[0-9a-f-]{36}$/i.test(lastPart)) {
        resourceId = lastPart;
      }
    }

    // Get IP address
    const ipAddress =
      c.req.header('X-Forwarded-For')?.split(',')[0]?.trim() ||
      c.req.header('X-Real-IP') ||
      'unknown';

    // Create audit log asynchronously (don't block response)
    createAuditLog({
      userId: user.id,
      action,
      resource,
      resourceId,
      ipAddress,
    }).catch((err) => console.error('Audit log error:', err));
  };
}

/**
 * Audit middleware for login/logout actions
 * Special handling for auth events.
 */
export function auditAuth(action: 'login' | 'logout' | 'register') {
  return async (c: Context, next: Next) => {
    const ipAddress =
      c.req.header('X-Forwarded-For')?.split(',')[0]?.trim() ||
      c.req.header('X-Real-IP') ||
      'unknown';

    // For login, we need to capture the response to get user info
    if (action === 'login') {
      // Clone response to read body
      const originalResponse = c.res.clone();

      try {
        const body = await originalResponse.json();
        if (body.success && body.data?.user?.id) {
          await createAuditLog({
            userId: body.data.user.id,
            action: 'login',
            resource: 'auth',
            details: { success: true },
            ipAddress,
          });
        }
      } catch {
        // Response already consumed or error
      }

      return;
    }

    // For logout, get user from context
    if (action === 'logout') {
      const user = c.get('user');
      if (user) {
        await createAuditLog({
          userId: user.id,
          action: 'logout',
          resource: 'auth',
          ipAddress,
        }).catch((err) => console.error('Audit log error:', err));
      }
      return;
    }

    await next();
  };
}

/**
 * Get client IP address from request
 */
export function getClientIp(c: Context): string {
  return (
    c.req.header('X-Forwarded-For')?.split(',')[0]?.trim() ||
    c.req.header('X-Real-IP') ||
    'unknown'
  );
}

