    expect(body.user.id).toBe(testUserId);
  });
});

describe('Audit Log', () => {
  let testUserId: string;

  beforeAll(async () => {
    // Create a minimal user for audit logs
    const testRoleId = uuid();
    await db.insert(roles).values({
      id: testRoleId,
      name: '审计角色',
      permissions: JSON.stringify({}),
      isSystem: false,
      createdAt: new Date().toISOString(),
    });

    testUserId = uuid();
    await db.insert(users).values({
      id: testUserId,
      username: 'audittestuser',
      email: 'audit@example.com',
      passwordHash: 'hash',
      displayName: '审计测试用户',
      roleId: testRoleId,
      status: 'active',
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    });
  });

  afterAll(async () => {
    await db.delete(auditLogs).where(eq(auditLogs.userId, testUserId));
    await db.delete(users).where(eq(users.id, testUserId));
  });

  test('should create audit log entry', async () => {
    await createAuditLog({
      userId: testUserId,
      action: 'create',
      resource: 'patient',
      resourceId: 'test-resource-id',
      details: { name: '测试患者' },
      ipAddress: '127.0.0.1',
    });

    const logs = await db.query.auditLogs.findMany({
      where: eq(auditLogs.userId, testUserId),
    });

    expect(logs.length).toBeGreaterThan(0);
    const lastLog = logs[logs.length - 1];
    expect(lastLog.action).toBe('create');
    expect(lastLog.resource).toBe('patient');
    expect(lastLog.resourceId).toBe('test-resource-id');
  });

  test('should handle audit log creation failure gracefully', async () => {
    // This should not throw even with invalid data
    await createAuditLog({
      userId: 'non-existent-user-id',
      action: 'test',
      resource: 'test',
    });

    // The test passes if no error is thrown
    expect(true).toBe(true);
  });
});

