import { Context, Next } from 'hono';
import { db } from '../db';
import { users, roles, sessions } from '../db/schema';
import { eq, and } from 'drizzle-orm';

// Extend Hono context to include user info
declare module 'hono' {
  interface ContextVariableMap {
    user: {
      id: string;
      username: string;
      email: string;
      displayName: string;
      avatar: string | null;
      roleId: string | null;
      status: string;
      role: {
        id: string;
        name: string;
        permissions: Record<string, Record<string, boolean>>;
      } | null;
    };
    sessionId: string;
  }
}

/**
 * Authentication middleware
 * Validates Bearer token from Authorization header,
 * checks session validity in database, and attaches user info to context.
 */
export async function authMiddleware(c: Context, next: Next) {
  const authHeader = c.req.header('Authorization');

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return c.json(
      { success: false, message: '未授权：缺少 Authorization 头' },
      401
    );
  }

  const token = authHeader.slice(7); // Remove 'Bearer ' prefix

  if (!token) {
    return c.json(
      { success: false, message: '未授权：Token 为空' },
      401
    );
  }

  try {
    // Find session by token
    const session = await db
      .select()
      .from(sessions)
      .where(eq(sessions.token, token))
      .limit(1);

    if (!session || session.length === 0) {
      return c.json(
        { success: false, message: '未授权：无效的 Token' },
        401
      );
    }

    const sessionData = session[0];

    // Check if session is expired
    const expiresAt = new Date(sessionData.expiresAt);
    if (expiresAt < new Date()) {
      // Clean up expired session
      await db.delete(sessions).where(eq(sessions.id, sessionData.id));
      return c.json(
        { success: false, message: '未授权：会话已过期，请重新登录' },
        401
      );
    }

    // Find user
    const userResult = await db
      .select()
      .from(users)
      .where(eq(users.id, sessionData.userId))
      .limit(1);

    if (!userResult || userResult.length === 0) {
      return c.json(
        { success: false, message: '未授权：用户不存在' },
        401
      );
    }

    const user = userResult[0];

    // Check if user is active
    if (user.status !== 'active') {
      return c.json(
        { success: false, message: '账号已被禁用，请联系管理员' },
        403
      );
    }

    // Find role
    let roleData = null;
    if (user.roleId) {
      const roleResult = await db
        .select()
        .from(roles)
        .where(eq(roles.id, user.roleId))
        .limit(1);

      if (roleResult && roleResult.length > 0) {
        const role = roleResult[0];
        let permissions: Record<string, Record<string, boolean>> = {};
        try {
          permissions = typeof role.permissions === 'string'
            ? JSON.parse(role.permissions)
            : (role.permissions || {});
        } catch {
          permissions = {};
        }

        roleData = {
          id: role.id,
          name: role.name,
          permissions,
        };
      }
    }

    // Attach user info to context
    c.set('user', {
      id: user.id,
      username: user.username,
      email: user.email,
      displayName: user.displayName,
      avatar: user.avatar,
      roleId: user.roleId,
      status: user.status,
      role: roleData,
    });
    c.set('sessionId', sessionData.id);

    await next();
  } catch (error) {
    console.error('Auth middleware error:', error);
    return c.json(
      { success: false, message: '服务器错误：认证失败' },
      500
    );
  }
}

/**
 * Role-based access control middleware factory
 * Creates middleware that checks if user has required permission.
 *
 * @param module - The module to check permission for (e.g., 'patients', 'studies', 'reports')
 * @param action - The action to check (e.g., 'create', 'read', 'update', 'delete')
 */
export function requirePermission(module: string, action: string) {
  return async (c: Context, next: Next) => {
    const user = c.get('user');

    if (!user) {
      return c.json(
        { success: false, message: '未授权：用户信息未找到' },
        401
      );
    }

    // Admin users bypass permission checks
    if (user.role?.name === '管理员') {
      await next();
      return;
    }

    if (!user.role) {
      return c.json(
        { success: false, message: '权限不足：未分配角色' },
        403
      );
    }

    const permissions = user.role.permissions;
    const hasPermission = permissions?.[module]?.[action] === true;

    if (!hasPermission) {
      return c.json(
        {
          success: false,
          message: `权限不足：需要 ${module}:${action} 权限`,
        },
        403
      );
    }

    await next();
  };
}

/**
 * Optional auth middleware
 * Attaches user info if token is present, but doesn't block the request.
 */
export async function optionalAuth(c: Context, next: Next) {
  const authHeader = c.req.header('Authorization');

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    await next();
    return;
  }

  const token = authHeader.slice(7);

  if (!token) {
    await next();
    return;
  }

  try {
    // Find session by token
    const session = await db
      .select()
      .from(sessions)
      .where(eq(sessions.token, token))
      .limit(1);

    if (!session || session.length === 0) {
      await next();
      return;
    }

    const sessionData = session[0];

    // Check if session is expired
    if (new Date(sessionData.expiresAt) < new Date()) {
      await next();
      return;
    }

    // Find user
    const userResult = await db
      .select()
      .from(users)
      .where(eq(users.id, sessionData.userId))
      .limit(1);

    if (!userResult || userResult.length === 0) {
      await next();
      return;
    }

    const user = userResult[0];

    // Check if user is active
    if (user.status !== 'active') {
      await next();
      return;
    }

    // Find role
    let roleData = null;
    if (user.roleId) {
      const roleResult = await db
        .select()
        .from(roles)
        .where(eq(roles.id, user.roleId))
        .limit(1);

      if (roleResult && roleResult.length > 0) {
        const role = roleResult[0];
        let permissions: Record<string, Record<string, boolean>> = {};
        try {
          permissions = typeof role.permissions === 'string'
            ? JSON.parse(role.permissions)
            : (role.permissions || {});
        } catch {
          permissions = {};
        }

        roleData = {
          id: role.id,
          name: role.name,
          permissions,
        };
      }
    }

    c.set('user', {
      id: user.id,
      username: user.username,
      email: user.email,
      displayName: user.displayName,
      avatar: user.avatar,
      roleId: user.roleId,
      status: user.status,
      role: roleData,
    });
    c.set('sessionId', sessionData.id);
  } catch (error) {
    // Silently fail for optional auth
    console.warn('Optional auth failed:', error);
  }

  await next();
}

