import { describe, test, expect, beforeAll, afterAll, beforeEach } from 'bun:test';
import { Hono } from 'hono';
import { authMiddleware, requirePermission, optionalAuth } from '../auth';
import { createAuditLog } from '../audit';
import { createTables } from '../../db/setup';
import { setDb } from '../../db';
import { users, roles, sessions, auditLogs } from '../../db/schema';
import { v4 as uuid } from 'uuid';
import { eq } from 'drizzle-orm';
import type { BunSQLiteDatabase } from 'drizzle-orm/bun-sqlite';

// Shared test database
let db: BunSQLiteDatabase<any>;
let sqlite: any;

// Test app setup
function createTestApp() {
  const app = new Hono();

  // Public route
  app.get('/public', (c) => c.json({ message: 'public' }));

  // Protected route
  app.get('/protected', authMiddleware, (c) => {
    const user = c.get('user');
    return c.json({ user });
  });

  // Permission-protected route
  app.get('/admin-only', authMiddleware, requirePermission('users', 'create'), (c) => {
    return c.json({ message: 'admin only' });
  });

  // Optional auth route
  app.get('/optional', optionalAuth, (c) => {
    const user = c.get('user');
    return c.json({ user: user || null });
  });

  return app;
}

// Test data IDs
let adminRoleId: string;
let testRoleId: string;
let testUserId: string;
let adminUserId: string;

beforeAll(async () => {
  // Create test database
  const result = createTables(':memory:');
  db = result.db;
  sqlite = result.sqlite;

  // Set the test database
  setDb(db, sqlite);

  // Create admin role
  adminRoleId = uuid();
  await db.insert(roles).values({
    id: adminRoleId,
    name: '管理员',
    description: '管理员',
    permissions: JSON.stringify({}),
    isSystem: true,
    createdAt: new Date().toISOString(),
  });

  // Create test role with specific permissions
  testRoleId = uuid();
  await db.insert(roles).values({
    id: testRoleId,
    name: '测试角色',
    description: '用于测试',
    permissions: JSON.stringify({
      patients: { create: true, read: true, update: true, delete: false },
      users: { create: false, read: true, update: false, delete: false },
    }),
    isSystem: false,
    createdAt: new Date().toISOString(),
  });

  // Create test user
  testUserId = uuid();
  const passwordHash = await Bun.password.hash('test123');
  await db.insert(users).values({
    id: testUserId,
    username: 'testuser',
    email: 'test@example.com',
    passwordHash,
    displayName: '测试用户',
    roleId: testRoleId,
    status: 'active',
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  });

  // Create admin user
  adminUserId = uuid();
  const adminPasswordHash = await Bun.password.hash('admin123');
  await db.insert(users).values({
    id: adminUserId,
    username: 'testadmin',
    email: 'testadmin@example.com',
    passwordHash: adminPasswordHash,
    displayName: '测试管理员',
    roleId: adminRoleId,
    status: 'active',
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  });
});

afterAll(async () => {
  // Clean up test data
  await db.delete(auditLogs);
  await db.delete(sessions);
  await db.delete(users);
  await db.delete(roles);
  sqlite?.close();
});

describe('Auth Middleware', () => {
  let testApp: Hono;

  beforeEach(async () => {
    testApp = createTestApp();
    // Clean up sessions before each test
    await db.delete(sessions);
  });

  test('should reject request without Authorization header', async () => {
    const res = await testApp.request('/protected');
    expect(res.status).toBe(401);
    const body = await res.json();
    expect(body.success).toBe(false);
    expect(body.message).toContain('Authorization');
  });

  test('should reject request with invalid token format', async () => {
    const res = await testApp.request('/protected', {
      headers: { Authorization: 'InvalidToken' },
    });
    expect(res.status).toBe(401);
  });

  test('should reject request with empty Bearer token', async () => {
    const res = await testApp.request('/protected', {
      headers: { Authorization: 'Bearer ' },
    });
    expect(res.status).toBe(401);
  });

  test('should reject request with non-existent token', async () => {
    const res = await testApp.request('/protected', {
      headers: { Authorization: 'Bearer non-existent-token' },
    });
    expect(res.status).toBe(401);
    const body = await res.json();
    expect(body.message).toContain('无效');
  });

  test('should reject request with expired session', async () => {
    // Create expired session
    const expiredToken = uuid();
    await db.insert(sessions).values({
      id: uuid(),
      userId: testUserId,
      token: expiredToken,
      refreshToken: uuid(),
      expiresAt: new Date(Date.now() - 1000 * 60 * 60).toISOString(), // 1 hour ago
      createdAt: new Date().toISOString(),
    });

    const res = await testApp.request('/protected', {
      headers: { Authorization: `Bearer ${expiredToken}` },
    });
    expect(res.status).toBe(401);
    const body = await res.json();
    expect(body.message).toContain('过期');
  });

  test('should reject request for disabled user', async () => {
    // Disable user
    await db.update(users)
      .set({ status: 'disabled' })
      .where(eq(users.id, testUserId));

    // Create valid session
    const validToken = uuid();
    await db.insert(sessions).values({
      id: uuid(),
      userId: testUserId,
      token: validToken,
      refreshToken: uuid(),
      expiresAt: new Date(Date.now() + 1000 * 60 * 60 * 24).toISOString(),
      createdAt: new Date().toISOString(),
    });

    const res = await testApp.request('/protected', {
      headers: { Authorization: `Bearer ${validToken}` },
    });
    expect(res.status).toBe(403);
    const body = await res.json();
    expect(body.message).toContain('禁用');

    // Re-enable user
    await db.update(users)
      .set({ status: 'active' })
      .where(eq(users.id, testUserId));
  });

  test('should accept valid token and attach user to context', async () => {
    const validToken = uuid();
    await db.insert(sessions).values({
      id: uuid(),
      userId: testUserId,
      token: validToken,
      refreshToken: uuid(),
      expiresAt: new Date(Date.now() + 1000 * 60 * 60 * 24).toISOString(),
      createdAt: new Date().toISOString(),
    });

    const res = await testApp.request('/protected', {
      headers: { Authorization: `Bearer ${validToken}` },
    });
    expect(res.status).toBe(200);
    const body = await res.json();
    expect(body.user).toBeDefined();
    expect(body.user.id).toBe(testUserId);
    expect(body.user.username).toBe('testuser');
    expect(body.user.role).toBeDefined();
    expect(body.user.role.name).toBe('测试角色');
  });

  test('should allow access to public route without token', async () => {
    const res = await testApp.request('/public');
    expect(res.status).toBe(200);
    const body = await res.json();
    expect(body.message).toBe('public');
  });
});

describe('requirePermission Middleware', () => {
  let testApp: Hono;
  let testSessionToken: string;

  beforeEach(async () => {
    testApp = createTestApp();
    await db.delete(sessions);

    // Create valid session for test user
    testSessionToken = uuid();
    await db.insert(sessions).values({
      id: uuid(),
      userId: testUserId,
      token: testSessionToken,
      refreshToken: uuid(),
      expiresAt: new Date(Date.now() + 1000 * 60 * 60 * 24).toISOString(),
      createdAt: new Date().toISOString(),
    });
  });

  test('should reject when user lacks required permission', async () => {
    // users:create is false in permissions
    const res = await testApp.request('/admin-only', {
      headers: { Authorization: `Bearer ${testSessionToken}` },
    });
    expect(res.status).toBe(403);
    const body = await res.json();
    expect(body.message).toContain('权限不足');
  });

  test('should allow admin users to bypass permission checks', async () => {
    const adminToken = uuid();
    await db.insert(sessions).values({
      id: uuid(),
      userId: adminUserId,
      token: adminToken,
      refreshToken: uuid(),
      expiresAt: new Date(Date.now() + 1000 * 60 * 60 * 24).toISOString(),
      createdAt: new Date().toISOString(),
    });

    const res = await testApp.request('/admin-only', {
      headers: { Authorization: `Bearer ${adminToken}` },
    });
    expect(res.status).toBe(200);
  });
});

describe('optionalAuth Middleware', () => {
  let testApp: Hono;

  beforeEach(async () => {
    testApp = createTestApp();
    await db.delete(sessions);
  });

  test('should allow access without token', async () => {
    const res = await testApp.request('/optional');
    expect(res.status).toBe(200);
    const body = await res.json();
    expect(body.user).toBeNull();
  });

  test('should attach user if valid token provided', async () => {
    const token = uuid();
    await db.insert(sessions).values({
      id: uuid(),
      userId: testUserId,
      token,
      refreshToken: uuid(),
      expiresAt: new Date(Date.now() + 1000 * 60 * 60 * 24).toISOString(),
      createdAt: new Date().toISOString(),
    });

    const res = await testApp.request('/optional', {
      headers: { Authorization: `Bearer ${token}` },
    });
    expect(res.status).toBe(200);
    const body = await res.json();
    expect(body.user).toBeDefined();
    expect(body.user.id).toBe(testUserId);
  });
});

describe('Audit Log', () => {
  test('should create audit log entry', async () => {
    await createAuditLog({
      userId: testUserId,
      action: 'create',
      resource: 'patient',
      resourceId: 'test-resource-id',
      details: { name: '测试患者' },
      ipAddress: '127.0.0.1',
    });

    const logs = await db.query.auditLogs.findMany({
      where: eq(auditLogs.userId, testUserId),
    });

    expect(logs.length).toBeGreaterThan(0);
    const lastLog = logs[logs.length - 1];
    expect(lastLog.action).toBe('create');
    expect(lastLog.resource).toBe('patient');
    expect(lastLog.resourceId).toBe('test-resource-id');
  });

  test('should handle audit log creation failure gracefully', async () => {
    // This should not throw even with invalid data
    await createAuditLog({
      userId: 'non-existent-user-id',
      action: 'test',
      resource: 'test',
    });

    // The test passes if no error is thrown
    expect(true).toBe(true);
  });
});
